+/// Binary cross-entropy loss
+fn binary_cross_entropy(prediction: f32, target: f32) -> f32 {
+    let eps = 1e-7;
+    let pred = prediction.clamp(eps, 1.0 - eps);
+    -target * pred.ln() - (1.0 - target) * (1.0 - pred).ln()
+}
