+/// Generate teacher predictions for knowledge distillation
+pub fn generate_teacher_predictions(
+    teacher: &FastGRNN,
+    features: &[Vec<f32>],
+    temperature: f32,
+) -> Result<Vec<f32>> {
+    features
+        .iter()
+        .map(|feature| {
+            let logit = teacher.forward(feature, None)?;
+            // Apply temperature scaling
+            Ok(temperature_softmax(logit, temperature))
+        })
+        .collect()
+}
