+        assert_eq!(means.len(), 3);
+        assert_eq!(stds.len(), 3);
+
+        // Check that normalized features have mean ~0 and std ~1
+        let sum: f32 = dataset.features.iter().map(|f| f[0]).sum();
+        let mean = sum / dataset.len() as f32;
+        assert!((mean.abs()) < 1e-5);
+    }
